#include<bits/stdc++.h>
using namespace std;

int n;
int m[105], a[105], y[505][505];
bool flag[505];
int in[505];
int ans = 0;
queue<int> q;
int main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
		cin >> m[i];
		for (int j = 1; j <= m[i]; j++) {
			int x;
			cin >> x;
			if (x == a[i]) continue;
			y[a[i]][x] = 1;
			in[x]++;
		}
		flag[a[i]] = 1;
	}
	for (int i = 0; i <= 500; i++) {
		if (in[i] == 0) {
			q.push(i);
		}
	}
	while (!q.empty()){
        int x=q.front();
        q.pop();
        for(int i=0;i<=500;i++){
            if(y[x][i]==1){
                in[i]--;
                y[x][i]=0;
                if(in[i]==0){
                    q.push(i);
                }
            }
        }
        if(flag[x]){
            ans++;
        }
    }
    if(ans==n){
        cout<<"YES";
    }else{
        cout<<n-ans;
    }
	return 0;
}
